  169: [
    { key: "red", description: "" },
    { key: "green", description: "" },
    { key: "blue", description: "" },
    { key: "yellow", description: "" },
    { key: "gold", description: "会用增加到2对的翅膀在黑暗中静静飞行。就算它从身旁飞过也不会察觉。" },
    { key: "silver", description: "脚也发展成翅膀，虽然因此可以高速飞行，但想停下来休息就很难了。" },
    { key: "crystal", description: "为了追求更快更安静地飞行，结果后肢也长成了翅膀。" },
    { key: "ruby", description: "只使用前肢或后肢挥动翅膀时，就表示它已经飞行了很长距离。疲劳时会交替挥动翅膀飞行。" },
    { key: "sapphire", description: "能用小到不仔细听就无法听到的振翅声悄悄接近它盯上的猎物。能用相当于后肢的翅膀抓住树枝休息。" },
    { key: "emerald", description: "后肢发展变成了翅膀。四肢的翅膀交替休息扇动的话，就可以一整天不休息地飞行。" },
    { key: "firered", description: "脚也发展成翅膀，虽然因此可以高速飞行，但想停下来休息就很难了。" },
    { key: "leafgreen", description: "会用增加到2对的翅膀在黑暗中静静飞行。就算它从身旁飞过也不会察觉。" },
    { key: "diamond", description: "4只翅膀能让它飞得更快更静。夜幕降临后就会开始活动。" },
    { key: "pearl", description: "因为双脚也变成了翅膀，所以飞行能力有了飞跃性的提升。" },
    { key: "platinum", description: "双脚也变成了翅膀，可以更加灵巧地飞翔，但是走路却变得很笨拙。" },
    { key: "heartgold", description: "会用增加到2对的翅膀在黑暗中静静飞行。就算它从身旁飞过也不会察觉。" },
    { key: "soulsilver", description: "脚也发展成翅膀，虽然因此可以高速飞行，但想停下来休息就很难了。" },
    { key: "black", description: "双脚也变成了翅膀，可以更加灵巧地飞翔，但是走路却变得很笨拙。" },
    { key: "white", description: "双脚也变成了翅膀，可以更加灵巧地飞翔，但是走路却变得很笨拙。" },
    { key: "x", description: "会用增加到2对的翅膀在黑暗中静静飞行。就算它从身旁飞过也不会察觉。" },
    { key: "y", description: "会用增加到2对的翅膀，以更快的速度静静飞行。能不被发现悄悄接近猎物。" },
    { key: "omega-ruby", description: "只使用前肢或后肢挥动翅膀时，就表示它已经飞行了很长距离。疲劳时会交替挥动翅膀飞行。" },
    { key: "alpha-sapphire", description: "能用小到不仔细听就无法听到的振翅声悄悄接近它盯上的猎物。能用相当于后肢的翅膀抓住树枝休息。" },
    { key: "lets-go-pikachu", description: "" },
    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "双脚变成了翅膀。可以悄无声息地高速飞行，亮出牙齿咬向猎物的后颈。" },
    { key: "shield", description: "可以自由地控制4根翅膀振翅而飞。即使在狭窄的洞窟内也能保持速度飞来飞去。" },
    { key: "brilliant-diamond", description: "4只翅膀能让它飞得更快更静。夜幕降临后就会开始活动。" },
    { key: "shining-pearl", description: "因为双脚也变成了翅膀，所以飞行能力有了飞跃性的提升。" },
    { key: "scarlet", description: "" },
    { key: "violet", description: "" },
    { key: "legends-z-a", description: "牙齿锋利，就算在黑暗中被它咬住吸血也不会感到疼痛，所以无法立刻发觉。" },
    { key: "sun", description: "连双脚也变成翅膀的结果就是不擅长在地上行动。只能爬着到处活动。" },
    { key: "moon", description: "用4根翅膀又快又静地飞行。在被发现之前一口咬住猎物。一瞬间就把血都吸掉。" },
    { key: "legends-arceus", description: "后肢变形成为翅膀。善于巧妙操纵四根翅膀，在洞窟内的狭缝中也能速度不减地一飞而过。" }
  ],
