    { key: "ruby", description: "盾甲茧的茧是由其口中吐出的细丝包裹身体后变硬而来的。它会在茧里准备进化。" },
    { key: "sapphire", description: "一旦动了就无法进化出强壮的身体，所以无论受到怎样的痛击都不会动。不过那时受到的疼痛它永远都不会忘记。" },
    { key: "emerald", description: "为了不被敌人找到而静静躲在大树叶的背面或者树枝间的空隙里。会用枯叶盖住作为伪装。" },
    { key: "firered", description: "由柔软的丝线形成的身体会随着时间逐渐变硬。如果出现裂纹就表示快要进化了。" },
    { key: "leafgreen", description: "由柔软的丝线形成的身体会随着时间逐渐变硬。如果出现裂纹就表示快要进化了。" },
    { key: "diamond", description: "茧内温度非常高，浑身细胞都在里面制造进化所需的能量。" },
    { key: "pearl", description: "身体被坚硬的茧包裹着，一动不动地忍受对手的攻击。不会忘记对手长什么样子。" },
    { key: "platinum", description: "就算进化了也不会忘记待在茧中时受到的攻击。一定会想方设法进行报复。" },
    { key: "heartgold", description: "一直承受着敌人的攻击，那时的痛苦会转化为力量，进化出强大的身体。" },
    { key: "soulsilver", description: "一直承受着敌人的攻击，那时的痛苦会转化为力量，进化出强大的身体。" },
    { key: "black", description: "就算进化了也不会忘记待在茧中时受到的攻击。一定会想方设法进行报复。" },
    { key: "white", description: "就算进化了也不会忘记待在茧中时受到的攻击。一定会想方设法进行报复。" },
    { key: "x", description: "由柔软的丝线形成的身体会随着时间逐渐变硬。如果出现裂纹就表示快要进化了。" },
    { key: "y", description: "就算进化了也不会忘记待在茧中时受到的攻击。一定会想方设法进行报复。" },
    { key: "omega-ruby", description: "盾甲茧的茧是由其口中吐出的细丝包裹身体后变硬而来的。它会在茧里准备进化。" },
    { key: "alpha-sapphire", description: "一旦动了就无法进化出强壮的身体，所以无论受到怎样的痛击都不会动。不过那时受到的疼痛它永远都不会忘记。" },
    { key: "lets-go-pikachu", description: "" },
    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "" },
    { key: "shield", description: "" },
    { key: "brilliant-diamond", description: "茧内温度非常高，浑身细胞都在里面制造进化所需的能量。" },
    { key: "shining-pearl", description: "身体被坚硬的茧包裹着，一动不动地忍受对手的攻击。不会忘记对手长什么样子。" },
    { key: "scarlet", description: "" },
    { key: "violet", description: "" },
    { key: "legends-z-a", description: "" },
    { key: "sun", description: "" },
    { key: "moon", description: "" },
    { key: "legends-arceus", description: "包裹全身的丝虽细，但强度十足，且色泽更胜甲壳茧的丝，以此织成的衣物被人们视为上品。" }
