    { key: "crystal", description: "" },
    { key: "ruby", description: "会悄悄地生活在洞窟深处。人们很惧怕它，认为它的眼睛在暗处发出诡异光芒时就会摄取人的魂魄。" },
    { key: "sapphire", description: "会用锋利的爪子从泥土中挖石头吃。石头中含有的成分会变成结晶，浮现在它身体的表面。" },
    { key: "emerald", description: "会用锐利的爪子在洞窟里挖横洞，找出宝石的原石之后把它吃掉。潜藏在黑暗里，鲜少能看得到它。" },
    { key: "firered", description: "会去吃宝石的结晶。双眼在漆黑一片的地方会发出宝石的光芒。" },
    { key: "leafgreen", description: "会去吃宝石的结晶。双眼在漆黑一片的地方会发出宝石的光芒。" },
    { key: "diamond", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "pearl", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "platinum", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "heartgold", description: "会在阴暗的洞窟建造住所，并用锋利的爪子挖宝石吃。" },
    { key: "soulsilver", description: "会在阴暗的洞窟建造住所，并用锋利的爪子挖宝石吃。" },
    { key: "black", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "white", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "x", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "y", description: "会在阴暗的洞窟建造住所，并用锋利的爪子挖宝石吃。" },
    { key: "omega-ruby", description: "会悄悄地生活在洞窟深处。人们很惧怕它，认为它的眼睛在暗处发出诡异光芒时就会摄取人的魂魄。" },
    { key: "alpha-sapphire", description: "会用锋利的爪子从泥土中挖石头吃。石头中含有的成分会变成结晶，浮现在它身体的表面。" },
    { key: "lets-go-pikachu", description: "" },
    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "宝石的眼睛发出诡异光芒时，就会摄取人的魂魄。是令人恐惧的宝可梦。" },
    { key: "shield", description: "会去吃宝石的结晶。双眼在漆黑一片的地方会发出宝石的光芒。" },
    { key: "brilliant-diamond", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "shining-pearl", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。" },
    { key: "scarlet", description: "会在阴暗的洞窟建造住所，并用锋利的爪子挖宝石吃。" },
    { key: "violet", description: "身体的表面会浮现出它所吃下的宝石成分。其花纹有无数的类型。" },
    { key: "legends-z-a", description: "潜伏于洞窟的阴暗处。在吃宝石的过程中，眼睛变成了宝石。受超级进化影响而巨大化的胸口的宝石，无论什么样的攻击都能反射回去。（超级进化）" },
    { key: "sun", description: "非常喜欢宝石，因此到处追着小碎钻。但却被尖牙陆鲨半路夺走。受超级进化影响而巨大化的胸口的宝石，无论什么样的攻击都能反射回去。（超级进化）" },
    { key: "moon", description: "宝石的眼睛发出诡异光芒时，就会摄取人的魂魄。是令人恐惧的宝可梦。因为巨大的宝石很沉，所以不擅长突然转变方向。来自后方的攻击是它的弱点。（超级进化）" },
    { key: "legends-arceus", description: "" }
