  306: [
    { key: "red", description: "" },
    { key: "green", description: "" },
    { key: "blue", description: "" },
    { key: "yellow", description: "" },
    { key: "gold", description: "" },
    { key: "silver", description: "" },
    { key: "crystal", description: "" },
    { key: "ruby", description: "会把一座山当做自己的领地，要是谁敢来胡闹，它就会毫不留情地将其痛揍一顿。总是在山间巡逻。" },
    { key: "sapphire", description: "当山体因滑坡或山火而变得荒芜起来时，它就会不断地运土、种上树苗，将自己的领地打扫得漂漂亮亮的。" },
    { key: "emerald", description: "由于头上铁制的角会一点一点变长，因此从角的长度可以得知波士可多拉的年龄。铠甲上的伤痕可说是它战斗的奖牌。" },
    { key: "firered", description: "占据大山的一处作为自己的地盘。对于擅自进入的外来者绝对不会放过，直接击倒。" },
    { key: "leafgreen", description: "占据大山的一处作为自己的地盘。对于擅自进入的外来者绝对不会放过，直接击倒。" },
    { key: "diamond", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "pearl", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "platinum", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "heartgold", description: "根据钢角的长度可以判断它的年龄。将整座山据为自己的地盘。" },
    { key: "soulsilver", description: "根据钢角的长度可以判断它的年龄。将整座山据为自己的地盘。" },
    { key: "black", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "white", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "x", description: "会把一整座山都当做自己领地。伤痕越多的波士可多拉经历的战斗就越多，所以不能轻视。" },
    { key: "y", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "omega-ruby", description: "会把一座山当做自己的领地，要是谁敢来胡闹，它就会毫不留情地将其痛揍一顿。总是在山间巡逻。" },
    { key: "alpha-sapphire", description: "当山体因滑坡或山火而变得荒芜起来时，它就会不断地运土、种上树苗，将自己的领地打扫得漂漂亮亮的。" },
    { key: "lets-go-pikachu", description: "" },
    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "会用能够刺穿铁板的锐利尖角在撞击敌人的同时攻击对方。" },
    { key: "shield", description: "很久以前，有位国王由于希望像波士可多拉一样强大而戴上了模仿它的头部制成的头盔。" },
    { key: "brilliant-diamond", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "shining-pearl", description: "会一边用钢角撞毁坚硬的岩盘，一边挖隧道寻找铁矿来作为自己的食物。" },
    { key: "scarlet", description: "" },
    { key: "violet", description: "" },
    { key: "legends-z-a", description: "会把一整座山都当做自己领地。伤痕越多的波士可多拉经历的战斗就越多，所以不能轻视。超级进化的能量使它体内的铁成分化为钢之装甲覆盖全身。（超级进化）" },
    { key: "sun", description: "" },
    { key: "moon", description: "" },
    { key: "legends-arceus", description: "" }
  ],
