    { key: "legends-z-a", description: "会用右手和左手分别放出2种不同的毒来进行攻击。香气越浓越有精神。" },
    { key: "sun", description: "" },
    { key: "moon", description: "" },
    { key: "legends-arceus", description: "长着美丽但带有剧毒的棘刺。本人的故乡自古流传着以此为信物向对手提出决斗要求的习俗。" }
