  319: [
    { key: "red", description: "" },
    { key: "green", description: "" },
    { key: "blue", description: "" },
    { key: "yellow", description: "" },
    { key: "gold", description: "" },
    { key: "silver", description: "" },
    { key: "crystal", description: "" },
    { key: "ruby", description: "被称为大海恶霸而让人闻风丧胆。有着折断后可以迅速再生的牙齿，单枪匹马就能把大型油船咬得稀巴烂。" },
    { key: "sapphire", description: "能从臀部的孔中喷出海水，以120公里的时速游动。弱点是游不了太长的距离。" },
    { key: "emerald", description: "性格凶暴且狡猾聪明的海之王者。拥有能减少水抗性的特殊皮肤，最高时速可以超过120公里。" },
    { key: "firered", description: "长着连铁都能咬断的牙的狂暴的海之王。通过从尾部喷射出海水来游动。" },
    { key: "leafgreen", description: "长着连铁都能咬断的牙的狂暴的海之王。通过从尾部喷射出海水来游动。" },
    { key: "diamond", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "pearl", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "platinum", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "heartgold", description: "它是会从臀部喷射出海水，并以120公里的时速四处游动的海中暴徒。" },
    { key: "soulsilver", description: "它是会从臀部喷射出海水，并以120公里的时速四处游动的海中暴徒。" },
    { key: "black", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "white", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "x", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "y", description: "它是会从臀部喷射出海水，并以120公里的时速四处游动的海中暴徒。" },
    { key: "omega-ruby", description: "被称为大海恶霸而让人闻风丧胆。有着折断后可以迅速再生的牙齿，单枪匹马就能把大型油船咬得稀巴烂。" },
    { key: "alpha-sapphire", description: "能从臀部的孔中喷出海水，以120公里的时速游动。弱点是游不了太长的距离。" },
    { key: "lets-go-pikachu", description: "" },
    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "嗅到猎物的味道后，会从臀部喷射海水，以120公里的时速发动袭击。" },
    { key: "shield", description: "被称为大海恶霸。进入它栖息海域的船只会无一例外地遭到袭击。" },
    { key: "brilliant-diamond", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "shining-pearl", description: "有着连铁板都能咬碎的牙齿，游动时，时速可达120公里。它的别名是大海恶霸。" },
    { key: "scarlet", description: "" },
    { key: "violet", description: "" },
    { key: "legends-z-a", description: "它是会从臀部喷射出海水，并以120公里的时速四处游动的海中暴徒。长在头部的尖刺是牙齿变化而来的。即使受伤折断，也能无数次地立刻长回来。（超级进化）" },
    { key: "sun", description: "以120公里的时速追击猎物，用连铁都能咬碎的牙齿捕杀。通常称之为大海恶霸。长在头部的尖刺是牙齿变化而来的。即使受伤折断，也能无数次地立刻长回来。（超级进化）" },
    { key: "moon", description: "过去，它的背鳍被当做贵重的食材，因此有着被滥捕的悲惨历史。由于超级进化，好斗的本性暴露无遗。黄色的花纹是过去历次战斗的伤痕。（超级进化）" },
    { key: "legends-arceus", description: "" }
  ],
