  334: [
    { key: "red", description: "" },
    { key: "green", description: "" },
    { key: "blue", description: "" },
    { key: "yellow", description: "" },
    { key: "gold", description: "" },
    { key: "silver", description: "" },
    { key: "crystal", description: "" },
    { key: "ruby", description: "会混在棉花云里在空中起舞。如果用通透的声音鸣出旋律，就会让听者心醉神迷，仿佛置身梦境。" },
    { key: "sapphire", description: "会用优美的高音歌唱的宝可梦。能用棉花云一样的翅膀借助上升气流飞向高空。" },
    { key: "emerald", description: "哼唱出优美的女高音。在蓝天与白云的交界处飞行。能从口中吐出灼热的火球。" },
    { key: "firered", description: "如果在远离人烟的深山中听到了美妙的音色，那就是七夕青鸟的哼唱。" },
    { key: "leafgreen", description: "如果在远离人烟的深山中听到了美妙的音色，那就是七夕青鸟的哼唱。" },
    { key: "diamond", description: "在天空飞翔的身姿看上去就像棉花云一样。会用高音哼唱旋律。" },
    { key: "pearl", description: "在天空飞翔的身姿看上去就像棉花云一样。会用高音哼唱旋律。" },
    { key: "platinum", description: "有了与之心意相通的人时候，会用柔软美丽的翅膀包裹对方轻轻哼唱。" },
    { key: "heartgold", description: "会悠然地飞翔在天空之中。听见七夕青鸟优美的哼唱，就会让人心醉神迷，仿佛置身梦境。" },
    { key: "soulsilver", description: "会悠然地飞翔在天空之中。听见七夕青鸟优美的哼唱，就会让人心醉神迷，仿佛置身梦境。" },
    { key: "black", description: "当它有了心意相通的人时，会用柔软又美丽的翅膀轻轻包裹对方并哼唱。" },
    { key: "white", description: "当它有了心意相通的人时，会用柔软又美丽的翅膀轻轻包裹对方并哼唱。" },
    { key: "x", description: "会悠然地飞翔在天空之中。听见七夕青鸟优美的哼唱，就会让人心醉神迷，仿佛置身梦境。" },
    { key: "y", description: "在晴朗日子里会混在棉花云里自由地在空中飞来飞去，会用优美的高音歌唱。" },
    { key: "omega-ruby", description: "会混在棉花云里在空中起舞。如果用通透的声音鸣出旋律，就会让听者心醉神迷，仿佛置身梦境。" },
    { key: "alpha-sapphire", description: "会用优美的高音歌唱的宝可梦。能用棉花云一样的翅膀借助上升气流飞向高空。" },
    { key: "lets-go-pikachu", description: "" },
    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "一边舒适地在天空中飞翔，一边发出优美的哼唱，让听到之人都为之沉醉。" },
    { key: "shield", description: "虽然性情温顺，但如果被惹怒，就会用尖锐的叫声威吓对方，并且毫不留情地发动进攻。" },
    { key: "brilliant-diamond", description: "在天空飞翔的身姿看上去就像棉花云一样。会用高音哼唱旋律。" },
    { key: "shining-pearl", description: "在天空飞翔的身姿看上去就像棉花云一样。会用高音哼唱旋律。" },
    { key: "scarlet", description: "当它有了心意相通的人时，会用柔软又美丽的翅膀轻轻包裹对方并哼唱。" },
    { key: "violet", description: "在晴朗日子里会混在棉花云里自由地在空中飞来飞去，会用优美的高音歌唱。" },
    { key: "legends-z-a", description: "会悠然地飞翔在天空之中。听见七夕青鸟优美的哼唱，就会让人心醉神迷，仿佛置身梦境。羽毛有溶化般的触感，只需几根就能吊起翻斗车，十分强韧。（超级进化）" },
    { key: "sun", description: "" },
    { key: "moon", description: "" },
    { key: "legends-arceus", description: "" }
  ],
