  479: [
    { key: "red", description: "" },
    { key: "green", description: "" },
    { key: "blue", description: "" },
    { key: "yellow", description: "" },
    { key: "gold", description: "" },
    { key: "silver", description: "" },
    { key: "crystal", description: "" },
    { key: "ruby", description: "" },
    { key: "sapphire", description: "" },
    { key: "emerald", description: "" },
    { key: "firered", description: "" },
    { key: "leafgreen", description: "" },
    { key: "diamond", description: "身体由等离子构成。因潜入电器中搞恶作剧而闻名。" },
    { key: "pearl", description: "身体由等离子构成。因潜入电器中搞恶作剧而闻名。" },
    { key: "platinum", description: "如同电一般的身体能够进入到一部分机器里，并将其作为躯体来恶作剧。" },
    { key: "heartgold", description: "作为驱动特殊马达的动力能源而被长期研究的宝可梦。" },
    { key: "soulsilver", description: "作为驱动特殊马达的动力能源而被长期研究的宝可梦。" },
    { key: "black", description: "如同电一般的身体能够进入到一部分机器里，并将其作为躯体来恶作剧。" },
    { key: "white", description: "如同电一般的身体能够进入到一部分机器里，并将其作为躯体来恶作剧。" },
    { key: "x", description: "作为驱动特殊马达的动力能源而被长期研究的宝可梦。" },
    { key: "y", description: "身体由等离子构成。因潜入电器中搞恶作剧而闻名。" },
    { key: "omega-ruby", description: "作为驱动特殊马达的动力能源而被长期研究的宝可梦。" },
    { key: "alpha-sapphire", description: "身体由等离子构成。因潜入电器中搞恶作剧而闻名。" },
    { key: "lets-go-pikachu", description: "" },
    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "某位少年的发明促使人们开始制造各种活用洛托姆的机器 。（洛托姆的样子）钻进由特殊马达驱动的烤箱微波炉里的洛托姆。十分擅长控制火焰。（加热洛托姆）会让房间发大水。喜欢利用水来恶作剧的洛托姆。（清洗洛托姆）钻进由特殊马达驱动的电冰箱里的洛托姆。会吐出冷气战斗。（结冰洛托姆）会吹飞你重要的资料。喜欢利用刮风来恶作剧的洛托姆。（旋转洛托姆）钻进由特殊马达驱动的割草机里的洛托姆。会把割下的草到处乱撒。（切割洛托姆）" },
    { key: "shield", description: "会用由离子构成的身体潜入各种各样的机器里。最喜欢恶作剧吓人。（洛托姆的样子）会烤焦你最爱的衣服。喜欢用加热来恶作剧的洛托姆。（加热洛托姆）钻进由特殊马达驱动的洗衣机里的洛托姆。会放水威吓对手。（清洗洛托姆）会冻住浴缸里放好的水。喜欢用冷气来恶作剧的洛托姆。（结冰洛托姆）钻进由特殊马达驱动的电风扇里的洛托姆。会制造强风来吹飞敌人。（旋转洛托姆）会割掉你种好的花。喜欢与草有关的恶作剧的洛托姆。（切割洛托姆）" },
    { key: "brilliant-diamond", description: "身体由等离子构成。因潜入电器中搞恶作剧而闻名。" },
    { key: "shining-pearl", description: "身体由等离子构成。因潜入电器中搞恶作剧而闻名。" },
    { key: "scarlet", description: "如同电一般的身体能够进入到一部分机器里，并将其作为躯体来恶作剧。如果烤箱微波炉本身运转不良，钻进里边的洛托姆也会变得无精打采。（加热洛托姆）钻进洗衣机里的样子。会用水淹没四周，然后心满意足地点头。（清洗洛托姆）钻进冰箱里的样子。会用冷气冻结四周，然后愉快地跳来跳去。（结冰洛托姆）钻进电风扇里的样子。会吹飞四周的东西，然后发出得逞了的窃笑。（旋转洛托姆）成为了洛托姆图鉴的诞生契机的其中一个家电产品就是割草机。（切割洛托姆）" },
    { key: "violet", description: "作为驱动特殊马达的动力能源而被长期研究的宝可梦。钻进了烤箱微波炉的样子。会用高温将周围烤得焦黑，然后开心地大笑。（加热洛托姆）由于已经停止生产，能让洛托姆钻进去的洗衣机在市场上被高价买卖。（清洗洛托姆）装在冰箱里的特殊马达是让洛托姆发生形态变化的关键。（结冰洛托姆）虽然能让洛托姆钻进去的家电产品有好几种，但最先被研发出来的是电风扇。（旋转洛托姆）钻进割草机的样子。砍倒花草后，它会自信满满地耀武扬威。（切割洛托姆）" },
    { key: "legends-z-a", description: "身体由等离子构成。因潜入电器中搞恶作剧而闻名。钻进由特殊马达驱动的烤箱微波炉里的洛托姆。十分擅长控制火焰。（加热洛托姆）钻进由特殊马达驱动的洗衣机里的洛托姆。会放水威吓对手。（清洗洛托姆）钻进由特殊马达驱动的电冰箱里的洛托姆。会吐出冷气战斗。（结冰洛托姆）钻进由特殊马达驱动的电风扇里的洛托姆。会制造强风来吹飞敌人。（旋转洛托姆）钻进由特殊马达驱动的割草机里的洛托姆。会把割下的草到处乱撒。（切割洛托姆）" },
    { key: "sun", description: "" },
    { key: "moon", description: "" },
    { key: "legends-arceus", description: "看来像是靠电能运作的灵魂，怪异至极的宝可梦。天生聪慧，但喜欢恶作剧，需小心应付。（洛托姆的样子）藏身于怪异饭锅中的形态。此饭锅来历不明。是个会喷火来作恶的麻烦家伙。（加热洛托姆）藏身于奇特柜子中的形态。柜子原本的用途不得而知。是个会泼洒冷水来作恶的麻烦家伙。（清洗洛托姆）藏身于奇怪橱柜中的形态。橱柜由未知的物质所制成。是个会制造冰霜来作恶的麻烦家伙。（结冰洛托姆）藏身于神秘器具中的形态。器具的用途不得而知。是个会喷吐狂风来作恶的麻烦家伙。（旋转洛托姆）藏身于异样推车中的形态。推车的构造十分不可思议。是个会砍断草木来作恶的麻烦家伙。（切割洛托姆）" }
  ],
