    { key: "lets-go-eevee", description: "" },
    { key: "sword", description: "在海底飘荡的海藻吸收了沉船的零件后转生而成的幽灵宝可梦。" },
    { key: "shield", description: "把锚抛到海里，伏击猎物。会去捕捉巨大的吼鲸王，吸取它们的精气。" },
    { key: "brilliant-diamond", description: "" },
    { key: "shining-pearl", description: "" },
    { key: "scarlet", description: "" },
    { key: "violet", description: "" },
    { key: "legends-z-a", description: "" },
    { key: "sun", description: "咣咣地来回摆动巨大的船锚，连吼鲸王也能一击击倒。绿色的海藻是它的本体。" },
    { key: "moon", description: "在海上飘荡的海藻的魂魄转生而成。用海藻网罗海里的垃圾，维持身体。" },
    { key: "legends-arceus", description: "" }
