export function getPokedexDescriptions(id: number): PokemonPokedexDesc {
  return POKEDEX_DESCRIPTIONS[id] || []
}

/** 某只宝可梦是否存在图鉴介绍 */
export function hasPokedexDescriptions(id: number): boolean {
  return !!POKEDEX_DESCRIPTIONS[id]?.length
}